INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-mysql-single-0001', 'teacher-1', 'MySQL', 'InnoDB引擎', '难', 'single', 'InnoDB引擎的核心作用是什么？', '["InnoDB引擎是MySQL中的核心概念，在实际开发中有广泛应用","InnoDB引擎的性能开销极大，任何场景都不应使用","InnoDB引擎与MySQL没有任何关系，属于硬件领域","InnoDB引擎主要用于绕过接口参数校验"]', '["InnoDB引擎是MySQL中的核心概念，在实际开发中有广泛应用"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-mysql-single-0002', 'teacher-1', 'MySQL', '索引优化', '易', 'single', '索引优化的核心作用是什么？', '["索引优化可以完全替代数据库和服务器","索引优化会自动绕过所有安全校验和权限控制","索引优化已经被完全废弃，现代开发不再使用","索引优化能够有效解决MySQL中的相关技术问题"]', '["索引优化能够有效解决MySQL中的相关技术问题"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-mysql-single-0003', 'teacher-1', 'MySQL', '慢查询', '难', 'single', '以下哪项不属于慢查询的特性？', '["慢查询可以完全替代数据库和服务器","慢查询的性能开销极大，任何场景都不应使用","慢查询主要用于绕过接口参数校验","慢查询的核心价值在于提供统一的解决方案"]', '["慢查询的核心价值在于提供统一的解决方案"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-mysql-single-0004', 'teacher-1', 'MySQL', '主从复制', '易', 'single', '学习主从复制时应重点掌握的内容是？', '["主从复制的核心价值在于提供统一的解决方案","主从复制只与前端页面样式有关，与后端逻辑无关","主从复制只能用于测试环境，生产环境禁止使用","主从复制只能在单线程环境下使用"]', '["主从复制的核心价值在于提供统一的解决方案"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
