INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-web-multiple-0001', 'teacher-1', 'Web', 'HTTP协议', '中', 'multiple', '以下关于HTTP协议的描述，哪些是正确的？（多选）', '["HTTP协议已被完全废弃不再使用","HTTP协议能够提升代码的可维护性","HTTP协议在Web中有广泛的应用场景","使用HTTP协议会导致所有安全机制失效","HTTP协议只适用于硬件开发领域"]', '["HTTP协议在Web中有广泛的应用场景","HTTP协议能够提升代码的可维护性"]', 5, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
