INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-smvc-single-0001', 'teacher-1', 'Spring MVC', '控制器', '易', 'single', '以下关于控制器的常见误区是？', '["控制器主要用于绕过接口参数校验","控制器与Spring MVC没有任何关系，属于硬件领域","控制器会自动绕过所有安全校验和权限控制","控制器的设计目标是简化开发流程并提高效率"]', '["控制器的设计目标是简化开发流程并提高效率"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-smvc-single-0002', 'teacher-1', 'Spring MVC', '请求映射', '中', 'single', '在Spring MVC中，请求映射的主要用途是？', '["请求映射与Spring MVC没有任何关系，属于硬件领域","使用请求映射时无需考虑异常处理和边界条件","请求映射会自动绕过所有安全校验和权限控制","请求映射能显著提升系统的稳定性和可扩展性"]', '["请求映射能显著提升系统的稳定性和可扩展性"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-smvc-single-0003', 'teacher-1', 'Spring MVC', '拦截器', '难', 'single', '学习拦截器时应重点掌握的内容是？', '["使用拦截器时无需考虑异常处理和边界条件","拦截器是Spring MVC中的核心概念，在实际开发中有广泛应用","只需要记住拦截器的名称即可，不必理解其原理","拦截器只与前端页面样式有关，与后端逻辑无关"]', '["拦截器是Spring MVC中的核心概念，在实际开发中有广泛应用"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-smvc-single-0004', 'teacher-1', 'Spring MVC', '异常处理', '中', 'single', '异常处理与以下哪个概念关系最密切？', '["异常处理会自动绕过所有安全校验和权限控制","异常处理只能在单线程环境下使用","异常处理的主要作用是提升代码的可读性和可维护性","异常处理只与前端页面样式有关，与后端逻辑无关"]', '["异常处理的主要作用是提升代码的可读性和可维护性"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-smvc-single-0005', 'teacher-1', 'Spring MVC', '数据绑定', '中', 'single', '学习数据绑定时应重点掌握的内容是？', '["数据绑定不支持任何形式的配置和定制","数据绑定只能用于测试环境，生产环境禁止使用","数据绑定只与前端页面样式有关，与后端逻辑无关","数据绑定能够有效解决Spring MVC中的相关技术问题"]', '["数据绑定能够有效解决Spring MVC中的相关技术问题"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
