INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-smvc-coding-0029', 'teacher-1', 'Spring MVC', '跨域配置', '中', 'coding', '请编写代码，展示如何正确使用跨域配置。', '[]', '["// Spring MVC - 跨域配置 示例代码\\n// 以下代码展示了跨域配置的基本用法和应用场景\\n\\n/*\\n * 步骤1: 初始化相关配置和环境\\n * 步骤2: 使用跨域配置实现核心逻辑\\n * 步骤3: 添加异常处理和边界检查\\n * 步骤4: 测试验证功能正确性\\n */\\n\\n// 具体实现请参考Spring MVC相关文档\\n// 关键点: 跨域配置的正确配置和使用方法"]', 15, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-smvc-coding-0030', 'teacher-1', 'Spring MVC', '参数校验', '中', 'coding', '请编写一段代码，展示参数校验的核心用法。', '[]', '["// Spring MVC - 参数校验 示例代码\\n// 以下代码展示了参数校验的基本用法和应用场景\\n\\n/*\\n * 步骤1: 初始化相关配置和环境\\n * 步骤2: 使用参数校验实现核心逻辑\\n * 步骤3: 添加异常处理和边界检查\\n * 步骤4: 测试验证功能正确性\\n */\\n\\n// 具体实现请参考Spring MVC相关文档\\n// 关键点: 参数校验的正确配置和使用方法"]', 15, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-sboot-single-0001', 'teacher-1', 'Spring Boot', '自动配置', '中', 'single', '学习自动配置时应重点掌握的内容是？', '["自动配置与Spring Boot没有任何关系，属于硬件领域","自动配置的主要作用是提升代码的可读性和可维护性","自动配置只能用于测试环境，生产环境禁止使用","使用自动配置时无需考虑异常处理和边界条件"]', '["自动配置的主要作用是提升代码的可读性和可维护性"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-sboot-single-0002', 'teacher-1', 'Spring Boot', 'Starter', '中', 'single', '关于Starter的最佳实践，以下哪项正确？', '["只需要记住Starter的名称即可，不必理解其原理","Starter主要用于绕过接口参数校验","Starter只能在单线程环境下使用","Starter的设计目标是简化开发流程并提高效率"]', '["Starter的设计目标是简化开发流程并提高效率"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-sboot-single-0003', 'teacher-1', 'Spring Boot', 'Actuator', '中', 'single', '学习Actuator时应重点掌握的内容是？', '["Actuator通过合理的抽象和封装实现功能需求","只需要记住Actuator的名称即可，不必理解其原理","Actuator已经被完全废弃，现代开发不再使用","Actuator主要用于绕过接口参数校验"]', '["Actuator通过合理的抽象和封装实现功能需求"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-sboot-single-0004', 'teacher-1', 'Spring Boot', '配置属性', '中', 'single', '配置属性的核心作用是什么？', '["配置属性只能用于测试环境，生产环境禁止使用","配置属性的主要作用是提升代码的可读性和可维护性","配置属性与Spring Boot没有任何关系，属于硬件领域","配置属性的性能开销极大，任何场景都不应使用"]', '["配置属性的主要作用是提升代码的可读性和可维护性"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-sboot-single-0005', 'teacher-1', 'Spring Boot', '条件装配', '中', 'single', '以下哪个不是条件装配的优点？', '["条件装配的设计目标是简化开发流程并提高效率","条件装配只能用于测试环境，生产环境禁止使用","条件装配的性能开销极大，任何场景都不应使用","条件装配可以完全替代数据库和服务器"]', '["条件装配的设计目标是简化开发流程并提高效率"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-sboot-single-0006', 'teacher-1', 'Spring Boot', '启动流程', '易', 'single', '启动流程适合用在什么场景？', '["启动流程只与前端页面样式有关，与后端逻辑无关","使用启动流程时无需考虑异常处理和边界条件","启动流程通过合理的抽象和封装实现功能需求","启动流程主要用于绕过接口参数校验"]', '["启动流程通过合理的抽象和封装实现功能需求"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-sboot-single-0007', 'teacher-1', 'Spring Boot', '内嵌容器', '易', 'single', '内嵌容器解决的核心问题是什么？', '["内嵌容器会自动绕过所有安全校验和权限控制","内嵌容器只与前端页面样式有关，与后端逻辑无关","内嵌容器与Spring Boot没有任何关系，属于硬件领域","内嵌容器能够有效解决Spring Boot中的相关技术问题"]', '["内嵌容器能够有效解决Spring Boot中的相关技术问题"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-sboot-single-0008', 'teacher-1', 'Spring Boot', '日志配置', '易', 'single', '以下哪个不是日志配置的优点？', '["日志配置已经被完全废弃，现代开发不再使用","日志配置能显著提升系统的稳定性和可扩展性","日志配置可以完全替代数据库和服务器","日志配置主要用于绕过接口参数校验"]', '["日志配置能显著提升系统的稳定性和可扩展性"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-sboot-single-0009', 'teacher-1', 'Spring Boot', '安全集成', '中', 'single', '以下哪个不是安全集成的优点？', '["安全集成不支持任何形式的配置和定制","安全集成已经被完全废弃，现代开发不再使用","安全集成能够有效解决Spring Boot中的相关技术问题","安全集成会自动绕过所有安全校验和权限控制"]', '["安全集成能够有效解决Spring Boot中的相关技术问题"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-sboot-single-0010', 'teacher-1', 'Spring Boot', '部署打包', '中', 'single', '在Spring Boot中，部署打包的主要用途是？', '["部署打包主要用于绕过接口参数校验","部署打包会自动绕过所有安全校验和权限控制","部署打包可以完全替代数据库和服务器","部署打包能显著提升系统的稳定性和可扩展性"]', '["部署打包能显著提升系统的稳定性和可扩展性"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-sboot-single-0011', 'teacher-1', 'Spring Boot', '自动配置', '中', 'single', '自动配置与以下哪个概念关系最密切？', '["自动配置在Spring Boot领域被广泛采用，是必备技能","自动配置只能在单线程环境下使用","自动配置可以完全替代数据库和服务器","自动配置与Spring Boot没有任何关系，属于硬件领域"]', '["自动配置在Spring Boot领域被广泛采用，是必备技能"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-sboot-single-0012', 'teacher-1', 'Spring Boot', 'Starter', '易', 'single', '以下哪个不是Starter的优点？', '["Starter只与前端页面样式有关，与后端逻辑无关","Starter的核心价值在于提供统一的解决方案","使用Starter时无需考虑异常处理和边界条件","Starter不支持任何形式的配置和定制"]', '["Starter的核心价值在于提供统一的解决方案"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
