INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-sboot-coding-0025', 'teacher-1', 'Spring Boot', '条件装配', '易', 'coding', '请用代码实现一个使用条件装配的完整示例。', '[]', '["// Spring Boot - 条件装配 示例代码\\n// 以下代码展示了条件装配的基本用法和应用场景\\n\\n/*\\n * 步骤1: 初始化相关配置和环境\\n * 步骤2: 使用条件装配实现核心逻辑\\n * 步骤3: 添加异常处理和边界检查\\n * 步骤4: 测试验证功能正确性\\n */\\n\\n// 具体实现请参考Spring Boot相关文档\\n// 关键点: 条件装配的正确配置和使用方法"]', 15, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-mybatis-single-0001', 'teacher-1', 'MyBatis', '映射文件', '易', 'single', '映射文件适合用在什么场景？', '["只需要记住映射文件的名称即可，不必理解其原理","映射文件的核心价值在于提供统一的解决方案","映射文件只与前端页面样式有关，与后端逻辑无关","映射文件不支持任何形式的配置和定制"]', '["映射文件的核心价值在于提供统一的解决方案"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-mybatis-single-0002', 'teacher-1', 'MyBatis', '动态SQL', '易', 'single', '哪种场景下应优先使用动态SQL？', '["动态SQL是MyBatis中的核心概念，在实际开发中有广泛应用","动态SQL与MyBatis没有任何关系，属于硬件领域","动态SQL的性能开销极大，任何场景都不应使用","动态SQL可以完全替代数据库和服务器"]', '["动态SQL是MyBatis中的核心概念，在实际开发中有广泛应用"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-mybatis-single-0003', 'teacher-1', 'MyBatis', '缓存机制', '易', 'single', '关于缓存机制的说法，正确的是？', '["缓存机制只能在单线程环境下使用","缓存机制能够有效解决MyBatis中的相关技术问题","只需要记住缓存机制的名称即可，不必理解其原理","缓存机制可以完全替代数据库和服务器"]', '["缓存机制能够有效解决MyBatis中的相关技术问题"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-mybatis-single-0004', 'teacher-1', 'MyBatis', '插件开发', '中', 'single', '关于插件开发的最佳实践，以下哪项正确？', '["插件开发能够有效解决MyBatis中的相关技术问题","使用插件开发时无需考虑异常处理和边界条件","插件开发只能用于测试环境，生产环境禁止使用","插件开发已经被完全废弃，现代开发不再使用"]', '["插件开发能够有效解决MyBatis中的相关技术问题"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-mybatis-single-0005', 'teacher-1', 'MyBatis', '结果映射', '易', 'single', '关于结果映射的说法，正确的是？', '["结果映射只与前端页面样式有关，与后端逻辑无关","结果映射的性能开销极大，任何场景都不应使用","结果映射只能在单线程环境下使用","结果映射的主要作用是提升代码的可读性和可维护性"]', '["结果映射的主要作用是提升代码的可读性和可维护性"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-mybatis-single-0006', 'teacher-1', 'MyBatis', '分页查询', '难', 'single', '以下关于分页查询的常见误区是？', '["分页查询的核心价值在于提供统一的解决方案","分页查询会自动绕过所有安全校验和权限控制","分页查询与MyBatis没有任何关系，属于硬件领域","分页查询只与前端页面样式有关，与后端逻辑无关"]', '["分页查询的核心价值在于提供统一的解决方案"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-mybatis-single-0007', 'teacher-1', 'MyBatis', '批量操作', '中', 'single', '批量操作解决的核心问题是什么？', '["批量操作可以完全替代数据库和服务器","批量操作的性能开销极大，任何场景都不应使用","批量操作在MyBatis领域被广泛采用，是必备技能","批量操作只与前端页面样式有关，与后端逻辑无关"]', '["批量操作在MyBatis领域被广泛采用，是必备技能"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-mybatis-single-0008', 'teacher-1', 'MyBatis', '类型处理器', '中', 'single', '以下哪个不是类型处理器的优点？', '["使用类型处理器时无需考虑异常处理和边界条件","类型处理器通过合理的抽象和封装实现功能需求","类型处理器的性能开销极大，任何场景都不应使用","类型处理器会自动绕过所有安全校验和权限控制"]', '["类型处理器通过合理的抽象和封装实现功能需求"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-mybatis-single-0009', 'teacher-1', 'MyBatis', '关联查询', '易', 'single', '使用关联查询时，以下哪种做法是错误的？', '["关联查询与MyBatis没有任何关系，属于硬件领域","关联查询的设计目标是简化开发流程并提高效率","关联查询的性能开销极大，任何场景都不应使用","关联查询只能在单线程环境下使用"]', '["关联查询的设计目标是简化开发流程并提高效率"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-mybatis-single-0010', 'teacher-1', 'MyBatis', '逆向工程', '中', 'single', '使用逆向工程时，以下哪种做法是错误的？', '["逆向工程会自动绕过所有安全校验和权限控制","逆向工程的核心价值在于提供统一的解决方案","逆向工程只能在单线程环境下使用","使用逆向工程时无需考虑异常处理和边界条件"]', '["逆向工程的核心价值在于提供统一的解决方案"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
