INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-mybatis-single-0012', 'teacher-1', 'MyBatis', '动态SQL', '易', 'single', '关于动态SQL的描述，哪项是正确的？', '["动态SQL不支持任何形式的配置和定制","动态SQL只与前端页面样式有关，与后端逻辑无关","只需要记住动态SQL的名称即可，不必理解其原理","动态SQL在MyBatis领域被广泛采用，是必备技能"]', '["动态SQL在MyBatis领域被广泛采用，是必备技能"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-mybatis-single-0013', 'teacher-1', 'MyBatis', '缓存机制', '易', 'single', '以下哪项不属于缓存机制的特性？', '["使用缓存机制时无需考虑异常处理和边界条件","缓存机制在MyBatis领域被广泛采用，是必备技能","缓存机制已经被完全废弃，现代开发不再使用","只需要记住缓存机制的名称即可，不必理解其原理"]', '["缓存机制在MyBatis领域被广泛采用，是必备技能"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
