INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-fe-dev-single-0001', 'teacher-1', '前端开发', 'Webpack', '易', 'single', '关于Webpack的描述，哪项是正确的？', '["Webpack与前端开发没有任何关系，属于硬件领域","只需要记住Webpack的名称即可，不必理解其原理","Webpack不支持任何形式的配置和定制","Webpack是前端开发中的核心概念，在实际开发中有广泛应用"]', '["Webpack是前端开发中的核心概念，在实际开发中有广泛应用"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
