INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-fe-dev-single-0016', 'teacher-1', '前端开发', '路由', '难', 'single', '路由解决的核心问题是什么？', '["路由的性能开销极大，任何场景都不应使用","路由可以完全替代数据库和服务器","路由只与前端页面样式有关，与后端逻辑无关","路由能够有效解决前端开发中的相关技术问题"]', '["路由能够有效解决前端开发中的相关技术问题"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
