INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-fe-dev-single-0018', 'teacher-1', '前端开发', '单元测试', '中', 'single', '单元测试的核心作用是什么？', '["单元测试的设计目标是简化开发流程并提高效率","单元测试与前端开发没有任何关系，属于硬件领域","单元测试只能用于测试环境，生产环境禁止使用","单元测试的性能开销极大，任何场景都不应使用"]', '["单元测试的设计目标是简化开发流程并提高效率"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-fe-dev-single-0019', 'teacher-1', '前端开发', 'CI/CD', '中', 'single', '关于CI/CD的最佳实践，以下哪项正确？', '["CI/CD可以完全替代数据库和服务器","CI/CD会自动绕过所有安全校验和权限控制","CI/CD的主要作用是提升代码的可读性和可维护性","使用CI/CD时无需考虑异常处理和边界条件"]', '["CI/CD的主要作用是提升代码的可读性和可维护性"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-fe-dev-single-0020', 'teacher-1', '前端开发', '代码规范', '易', 'single', '哪种场景下应优先使用代码规范？', '["代码规范是前端开发中的核心概念，在实际开发中有广泛应用","代码规范只能用于测试环境，生产环境禁止使用","代码规范已经被完全废弃，现代开发不再使用","代码规范会自动绕过所有安全校验和权限控制"]', '["代码规范是前端开发中的核心概念，在实际开发中有广泛应用"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-fe-dev-single-0021', 'teacher-1', '前端开发', 'Webpack', '中', 'single', '学习Webpack时应重点掌握的内容是？', '["Webpack只与前端页面样式有关，与后端逻辑无关","使用Webpack时无需考虑异常处理和边界条件","Webpack不支持任何形式的配置和定制","Webpack能够有效解决前端开发中的相关技术问题"]', '["Webpack能够有效解决前端开发中的相关技术问题"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-fe-dev-single-0022', 'teacher-1', '前端开发', 'Babel', '中', 'single', '学习Babel时应重点掌握的内容是？', '["使用Babel时无需考虑异常处理和边界条件","Babel与前端开发没有任何关系，属于硬件领域","Babel只能在单线程环境下使用","Babel的主要作用是提升代码的可读性和可维护性"]', '["Babel的主要作用是提升代码的可读性和可维护性"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-fe-dev-single-0023', 'teacher-1', '前端开发', 'ESLint', '中', 'single', '以下哪个不是ESLint的优点？', '["ESLint是前端开发中的核心概念，在实际开发中有广泛应用","ESLint只能在单线程环境下使用","ESLint主要用于绕过接口参数校验","ESLint可以完全替代数据库和服务器"]', '["ESLint是前端开发中的核心概念，在实际开发中有广泛应用"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
