INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-js-single-0001', 'teacher-1', 'JavaScript', '闭包', '易', 'single', '哪种场景下应优先使用闭包？', '["闭包与JavaScript没有任何关系，属于硬件领域","闭包会自动绕过所有安全校验和权限控制","闭包只与前端页面样式有关，与后端逻辑无关","闭包的核心价值在于提供统一的解决方案"]', '["闭包的核心价值在于提供统一的解决方案"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-js-single-0002', 'teacher-1', 'JavaScript', '原型链', '中', 'single', '原型链与以下哪个概念关系最密切？', '["原型链会自动绕过所有安全校验和权限控制","原型链已经被完全废弃，现代开发不再使用","原型链只能在单线程环境下使用","原型链能够有效解决JavaScript中的相关技术问题"]', '["原型链能够有效解决JavaScript中的相关技术问题"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-js-single-0003', 'teacher-1', 'JavaScript', 'Promise', '易', 'single', '在JavaScript中，Promise的主要用途是？', '["Promise不支持任何形式的配置和定制","使用Promise时无需考虑异常处理和边界条件","Promise主要用于绕过接口参数校验","Promise通过合理的抽象和封装实现功能需求"]', '["Promise通过合理的抽象和封装实现功能需求"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-js-single-0004', 'teacher-1', 'JavaScript', 'async/await', '易', 'single', '哪种场景下应优先使用async/await？', '["async/await与JavaScript没有任何关系，属于硬件领域","async/await的性能开销极大，任何场景都不应使用","async/await在JavaScript领域被广泛采用，是必备技能","async/await主要用于绕过接口参数校验"]', '["async/await在JavaScript领域被广泛采用，是必备技能"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-js-single-0005', 'teacher-1', 'JavaScript', '事件循环', '中', 'single', '事件循环解决的核心问题是什么？', '["事件循环是JavaScript中的核心概念，在实际开发中有广泛应用","事件循环与JavaScript没有任何关系，属于硬件领域","事件循环会自动绕过所有安全校验和权限控制","事件循环已经被完全废弃，现代开发不再使用"]', '["事件循环是JavaScript中的核心概念，在实际开发中有广泛应用"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
