INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-js-single-0022', 'teacher-1', 'JavaScript', '原型链', '中', 'single', '原型链适合用在什么场景？', '["原型链主要用于绕过接口参数校验","原型链只能在单线程环境下使用","原型链的核心价值在于提供统一的解决方案","使用原型链时无需考虑异常处理和边界条件"]', '["原型链的核心价值在于提供统一的解决方案"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-js-single-0023', 'teacher-1', 'JavaScript', 'Promise', '中', 'single', '使用Promise时，以下哪种做法是错误的？', '["Promise通过合理的抽象和封装实现功能需求","Promise主要用于绕过接口参数校验","只需要记住Promise的名称即可，不必理解其原理","使用Promise时无需考虑异常处理和边界条件"]', '["Promise通过合理的抽象和封装实现功能需求"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-js-single-0024', 'teacher-1', 'JavaScript', 'async/await', '中', 'single', 'async/await的核心作用是什么？', '["async/await能够有效解决JavaScript中的相关技术问题","async/await与JavaScript没有任何关系，属于硬件领域","使用async/await时无需考虑异常处理和边界条件","只需要记住async/await的名称即可，不必理解其原理"]', '["async/await能够有效解决JavaScript中的相关技术问题"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-js-single-0025', 'teacher-1', 'JavaScript', '事件循环', '易', 'single', '以下哪个不是事件循环的优点？', '["事件循环会自动绕过所有安全校验和权限控制","事件循环能显著提升系统的稳定性和可扩展性","事件循环只能在单线程环境下使用","事件循环只与前端页面样式有关，与后端逻辑无关"]', '["事件循环能显著提升系统的稳定性和可扩展性"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
