INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-js-coding-0024', 'teacher-1', 'JavaScript', 'async/await', '易', 'coding', '请编写代码，展示如何正确使用async/await。', '[]', '["// JavaScript - async/await 示例代码\\n// 以下代码展示了async/await的基本用法和应用场景\\n\\n/*\\n * 步骤1: 初始化相关配置和环境\\n * 步骤2: 使用async/await实现核心逻辑\\n * 步骤3: 添加异常处理和边界检查\\n * 步骤4: 测试验证功能正确性\\n */\\n\\n// 具体实现请参考JavaScript相关文档\\n// 关键点: async/await的正确配置和使用方法"]', 15, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-js-coding-0025', 'teacher-1', 'JavaScript', '事件循环', '中', 'coding', '请用代码演示事件循环在实际项目中的应用。', '[]', '["// JavaScript - 事件循环 示例代码\\n// 以下代码展示了事件循环的基本用法和应用场景\\n\\n/*\\n * 步骤1: 初始化相关配置和环境\\n * 步骤2: 使用事件循环实现核心逻辑\\n * 步骤3: 添加异常处理和边界检查\\n * 步骤4: 测试验证功能正确性\\n */\\n\\n// 具体实现请参考JavaScript相关文档\\n// 关键点: 事件循环的正确配置和使用方法"]', 15, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-ts-single-0001', 'teacher-1', 'TypeScript', '类型系统', '易', 'single', '以下关于类型系统的常见误区是？', '["类型系统已经被完全废弃，现代开发不再使用","类型系统主要用于绕过接口参数校验","类型系统与TypeScript没有任何关系，属于硬件领域","类型系统的设计目标是简化开发流程并提高效率"]', '["类型系统的设计目标是简化开发流程并提高效率"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-ts-single-0002', 'teacher-1', 'TypeScript', '接口', '难', 'single', '接口适合用在什么场景？', '["接口可以完全替代数据库和服务器","接口与TypeScript没有任何关系，属于硬件领域","接口通过合理的抽象和封装实现功能需求","使用接口时无需考虑异常处理和边界条件"]', '["接口通过合理的抽象和封装实现功能需求"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-ts-single-0003', 'teacher-1', 'TypeScript', '泛型', '中', 'single', '使用泛型时，以下哪种做法是错误的？', '["泛型与TypeScript没有任何关系，属于硬件领域","泛型是TypeScript中的核心概念，在实际开发中有广泛应用","泛型只与前端页面样式有关，与后端逻辑无关","只需要记住泛型的名称即可，不必理解其原理"]', '["泛型是TypeScript中的核心概念，在实际开发中有广泛应用"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-ts-single-0004', 'teacher-1', 'TypeScript', '装饰器', '易', 'single', '以下哪个不是装饰器的优点？', '["装饰器只与前端页面样式有关，与后端逻辑无关","装饰器的性能开销极大，任何场景都不应使用","使用装饰器时无需考虑异常处理和边界条件","装饰器通过合理的抽象和封装实现功能需求"]', '["装饰器通过合理的抽象和封装实现功能需求"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
