INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-ts-coding-0025', 'teacher-1', 'TypeScript', '枚举', '难', 'coding', '请编写代码，展示如何正确使用枚举。', '[]', '["// TypeScript - 枚举 示例代码\\n// 以下代码展示了枚举的基本用法和应用场景\\n\\n/*\\n * 步骤1: 初始化相关配置和环境\\n * 步骤2: 使用枚举实现核心逻辑\\n * 步骤3: 添加异常处理和边界检查\\n * 步骤4: 测试验证功能正确性\\n */\\n\\n// 具体实现请参考TypeScript相关文档\\n// 关键点: 枚举的正确配置和使用方法"]', 15, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-html5-single-0001', 'teacher-1', 'HTML5', '语义化标签', '中', 'single', '以下哪项不属于语义化标签的特性？', '["语义化标签主要用于绕过接口参数校验","语义化标签能够有效解决HTML5中的相关技术问题","只需要记住语义化标签的名称即可，不必理解其原理","语义化标签的性能开销极大，任何场景都不应使用"]', '["语义化标签能够有效解决HTML5中的相关技术问题"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-html5-single-0002', 'teacher-1', 'HTML5', 'Canvas', '难', 'single', '学习Canvas时应重点掌握的内容是？', '["Canvas的核心价值在于提供统一的解决方案","Canvas的性能开销极大，任何场景都不应使用","只需要记住Canvas的名称即可，不必理解其原理","Canvas与HTML5没有任何关系，属于硬件领域"]', '["Canvas的核心价值在于提供统一的解决方案"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-html5-single-0003', 'teacher-1', 'HTML5', 'SVG', '难', 'single', '关于SVG的描述，哪项是正确的？', '["SVG主要用于绕过接口参数校验","SVG只与前端页面样式有关，与后端逻辑无关","SVG的主要作用是提升代码的可读性和可维护性","SVG只能在单线程环境下使用"]', '["SVG的主要作用是提升代码的可读性和可维护性"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-html5-single-0004', 'teacher-1', 'HTML5', '本地存储', '易', 'single', '以下哪个不是本地存储的优点？', '["本地存储与HTML5没有任何关系，属于硬件领域","本地存储只能用于测试环境，生产环境禁止使用","本地存储能够有效解决HTML5中的相关技术问题","本地存储主要用于绕过接口参数校验"]', '["本地存储能够有效解决HTML5中的相关技术问题"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-html5-single-0005', 'teacher-1', 'HTML5', 'Web Workers', '易', 'single', 'Web Workers的实现原理是什么？', '["Web Workers通过合理的抽象和封装实现功能需求","Web Workers不支持任何形式的配置和定制","Web Workers只与前端页面样式有关，与后端逻辑无关","Web Workers的性能开销极大，任何场景都不应使用"]', '["Web Workers通过合理的抽象和封装实现功能需求"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-html5-single-0006', 'teacher-1', 'HTML5', 'Geolocation', '易', 'single', '关于Geolocation的最佳实践，以下哪项正确？', '["Geolocation通过合理的抽象和封装实现功能需求","使用Geolocation时无需考虑异常处理和边界条件","Geolocation只能在单线程环境下使用","Geolocation不支持任何形式的配置和定制"]', '["Geolocation通过合理的抽象和封装实现功能需求"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-html5-single-0007', 'teacher-1', 'HTML5', '音视频', '易', 'single', '以下关于音视频的常见误区是？', '["音视频是HTML5中的核心概念，在实际开发中有广泛应用","音视频主要用于绕过接口参数校验","只需要记住音视频的名称即可，不必理解其原理","音视频会自动绕过所有安全校验和权限控制"]', '["音视频是HTML5中的核心概念，在实际开发中有广泛应用"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
