INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-html5-coding-0024', 'teacher-1', 'HTML5', '本地存储', '中', 'coding', '请编写代码解决一个涉及本地存储的实际问题。', '[]', '["// HTML5 - 本地存储 示例代码\\n// 以下代码展示了本地存储的基本用法和应用场景\\n\\n/*\\n * 步骤1: 初始化相关配置和环境\\n * 步骤2: 使用本地存储实现核心逻辑\\n * 步骤3: 添加异常处理和边界检查\\n * 步骤4: 测试验证功能正确性\\n */\\n\\n// 具体实现请参考HTML5相关文档\\n// 关键点: 本地存储的正确配置和使用方法"]', 15, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-html5-coding-0025', 'teacher-1', 'HTML5', 'Web Workers', '中', 'coding', '请编写代码，展示如何正确使用Web Workers。', '[]', '["// HTML5 - Web Workers 示例代码\\n// 以下代码展示了Web Workers的基本用法和应用场景\\n\\n/*\\n * 步骤1: 初始化相关配置和环境\\n * 步骤2: 使用Web Workers实现核心逻辑\\n * 步骤3: 添加异常处理和边界检查\\n * 步骤4: 测试验证功能正确性\\n */\\n\\n// 具体实现请参考HTML5相关文档\\n// 关键点: Web Workers的正确配置和使用方法"]', 15, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-css3-single-0001', 'teacher-1', 'CSS3', 'Flexbox', '易', 'single', '关于Flexbox的说法，正确的是？', '["Flexbox只与前端页面样式有关，与后端逻辑无关","Flexbox只能在单线程环境下使用","Flexbox的核心价值在于提供统一的解决方案","Flexbox主要用于绕过接口参数校验"]', '["Flexbox的核心价值在于提供统一的解决方案"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-css3-single-0002', 'teacher-1', 'CSS3', 'Grid', '难', 'single', '关于Grid的描述，哪项是正确的？', '["Grid的核心价值在于提供统一的解决方案","使用Grid时无需考虑异常处理和边界条件","Grid可以完全替代数据库和服务器","Grid不支持任何形式的配置和定制"]', '["Grid的核心价值在于提供统一的解决方案"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-css3-single-0003', 'teacher-1', 'CSS3', '动画', '中', 'single', '哪种场景下应优先使用动画？', '["使用动画时无需考虑异常处理和边界条件","动画与CSS3没有任何关系，属于硬件领域","动画主要用于绕过接口参数校验","动画的设计目标是简化开发流程并提高效率"]', '["动画的设计目标是简化开发流程并提高效率"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-css3-single-0004', 'teacher-1', 'CSS3', '过渡', '易', 'single', '关于过渡的说法，正确的是？', '["过渡已经被完全废弃，现代开发不再使用","过渡只能在单线程环境下使用","过渡能够有效解决CSS3中的相关技术问题","过渡主要用于绕过接口参数校验"]', '["过渡能够有效解决CSS3中的相关技术问题"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-css3-single-0005', 'teacher-1', 'CSS3', '变换', '易', 'single', '关于变换的最佳实践，以下哪项正确？', '["变换与CSS3没有任何关系，属于硬件领域","使用变换时无需考虑异常处理和边界条件","变换的主要作用是提升代码的可读性和可维护性","只需要记住变换的名称即可，不必理解其原理"]', '["变换的主要作用是提升代码的可读性和可维护性"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-css3-single-0006', 'teacher-1', 'CSS3', '媒体查询', '难', 'single', '媒体查询的实现原理是什么？', '["使用媒体查询时无需考虑异常处理和边界条件","媒体查询与CSS3没有任何关系，属于硬件领域","媒体查询能够有效解决CSS3中的相关技术问题","媒体查询主要用于绕过接口参数校验"]', '["媒体查询能够有效解决CSS3中的相关技术问题"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-css3-single-0007', 'teacher-1', 'CSS3', '变量', '难', 'single', '哪种场景下应优先使用变量？', '["变量通过合理的抽象和封装实现功能需求","变量只能在单线程环境下使用","变量已经被完全废弃，现代开发不再使用","变量的性能开销极大，任何场景都不应使用"]', '["变量通过合理的抽象和封装实现功能需求"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-css3-single-0008', 'teacher-1', 'CSS3', '伪元素', '易', 'single', '伪元素适合用在什么场景？', '["伪元素的性能开销极大，任何场景都不应使用","伪元素能显著提升系统的稳定性和可扩展性","只需要记住伪元素的名称即可，不必理解其原理","伪元素会自动绕过所有安全校验和权限控制"]', '["伪元素能显著提升系统的稳定性和可扩展性"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-css3-single-0009', 'teacher-1', 'CSS3', '选择器', '中', 'single', '选择器适合用在什么场景？', '["使用选择器时无需考虑异常处理和边界条件","选择器是CSS3中的核心概念，在实际开发中有广泛应用","选择器只能用于测试环境，生产环境禁止使用","选择器只能在单线程环境下使用"]', '["选择器是CSS3中的核心概念，在实际开发中有广泛应用"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-css3-single-0010', 'teacher-1', 'CSS3', '盒模型', '难', 'single', '在CSS3中，盒模型的主要用途是？', '["盒模型是CSS3中的核心概念，在实际开发中有广泛应用","盒模型可以完全替代数据库和服务器","只需要记住盒模型的名称即可，不必理解其原理","盒模型只与前端页面样式有关，与后端逻辑无关"]', '["盒模型是CSS3中的核心概念，在实际开发中有广泛应用"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
