INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-css3-single-0016', 'teacher-1', 'CSS3', '媒体查询', '中', 'single', '以下哪项不属于媒体查询的特性？', '["媒体查询主要用于绕过接口参数校验","媒体查询的设计目标是简化开发流程并提高效率","媒体查询已经被完全废弃，现代开发不再使用","只需要记住媒体查询的名称即可，不必理解其原理"]', '["媒体查询的设计目标是简化开发流程并提高效率"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-css3-single-0017', 'teacher-1', 'CSS3', '变量', '易', 'single', '关于变量的说法，正确的是？', '["变量可以完全替代数据库和服务器","只需要记住变量的名称即可，不必理解其原理","变量只与前端页面样式有关，与后端逻辑无关","变量通过合理的抽象和封装实现功能需求"]', '["变量通过合理的抽象和封装实现功能需求"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-css3-single-0018', 'teacher-1', 'CSS3', '伪元素', '中', 'single', '以下关于伪元素的常见误区是？', '["伪元素只能在单线程环境下使用","伪元素的性能开销极大，任何场景都不应使用","伪元素只与前端页面样式有关，与后端逻辑无关","伪元素能显著提升系统的稳定性和可扩展性"]', '["伪元素能显著提升系统的稳定性和可扩展性"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
