INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-vue2-single-0001', 'teacher-1', 'Vue 2', '组件', '易', 'single', '组件的实现原理是什么？', '["组件只能用于测试环境，生产环境禁止使用","组件主要用于绕过接口参数校验","只需要记住组件的名称即可，不必理解其原理","组件在Vue 2领域被广泛采用，是必备技能"]', '["组件在Vue 2领域被广泛采用，是必备技能"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
