INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-vue2-single-0024', 'teacher-1', 'Vue 2', '生命周期', '难', 'single', '哪种场景下应优先使用生命周期？', '["生命周期已经被完全废弃，现代开发不再使用","生命周期会自动绕过所有安全校验和权限控制","生命周期的主要作用是提升代码的可读性和可维护性","生命周期不支持任何形式的配置和定制"]', '["生命周期的主要作用是提升代码的可读性和可维护性"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
