INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-vue3-single-0001', 'teacher-1', 'Vue 3', 'Composition API', '易', 'single', '关于Composition API的描述，哪项是正确的？', '["Composition API已经被完全废弃，现代开发不再使用","使用Composition API时无需考虑异常处理和边界条件","Composition API会自动绕过所有安全校验和权限控制","Composition API是Vue 3中的核心概念，在实际开发中有广泛应用"]', '["Composition API是Vue 3中的核心概念，在实际开发中有广泛应用"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-vue3-single-0002', 'teacher-1', 'Vue 3', 'ref与reactive', '易', 'single', '关于ref与reactive的描述，哪项是正确的？', '["ref与reactive只能在单线程环境下使用","ref与reactive与Vue 3没有任何关系，属于硬件领域","ref与reactive已经被完全废弃，现代开发不再使用","ref与reactive能够有效解决Vue 3中的相关技术问题"]', '["ref与reactive能够有效解决Vue 3中的相关技术问题"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
