INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-vue3-coding-0025', 'teacher-1', 'Vue 3', 'Pinia', '易', 'coding', '请用代码实现一个使用Pinia的完整示例。', '[]', '["// Vue 3 - Pinia 示例代码\\n// 以下代码展示了Pinia的基本用法和应用场景\\n\\n/*\\n * 步骤1: 初始化相关配置和环境\\n * 步骤2: 使用Pinia实现核心逻辑\\n * 步骤3: 添加异常处理和边界检查\\n * 步骤4: 测试验证功能正确性\\n */\\n\\n// 具体实现请参考Vue 3相关文档\\n// 关键点: Pinia的正确配置和使用方法"]', 15, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-nodejs-single-0001', 'teacher-1', 'Node.js', '事件驱动', '难', 'single', '事件驱动的实现原理是什么？', '["只需要记住事件驱动的名称即可，不必理解其原理","事件驱动的核心价值在于提供统一的解决方案","使用事件驱动时无需考虑异常处理和边界条件","事件驱动与Node.js没有任何关系，属于硬件领域"]', '["事件驱动的核心价值在于提供统一的解决方案"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-nodejs-single-0002', 'teacher-1', 'Node.js', 'Stream', '中', 'single', '哪种场景下应优先使用Stream？', '["Stream是Node.js中的核心概念，在实际开发中有广泛应用","Stream的性能开销极大，任何场景都不应使用","Stream会自动绕过所有安全校验和权限控制","Stream只能用于测试环境，生产环境禁止使用"]', '["Stream是Node.js中的核心概念，在实际开发中有广泛应用"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-nodejs-single-0003', 'teacher-1', 'Node.js', 'Buffer', '中', 'single', 'Buffer适合用在什么场景？', '["Buffer不支持任何形式的配置和定制","Buffer可以完全替代数据库和服务器","只需要记住Buffer的名称即可，不必理解其原理","Buffer在Node.js领域被广泛采用，是必备技能"]', '["Buffer在Node.js领域被广泛采用，是必备技能"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-nodejs-single-0004', 'teacher-1', 'Node.js', '模块系统', '中', 'single', '关于模块系统的说法，正确的是？', '["模块系统只能用于测试环境，生产环境禁止使用","模块系统在Node.js领域被广泛采用，是必备技能","模块系统会自动绕过所有安全校验和权限控制","使用模块系统时无需考虑异常处理和边界条件"]', '["模块系统在Node.js领域被广泛采用，是必备技能"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-nodejs-single-0005', 'teacher-1', 'Node.js', 'Express', '中', 'single', 'Express的实现原理是什么？', '["Express只能在单线程环境下使用","Express会自动绕过所有安全校验和权限控制","Express在Node.js领域被广泛采用，是必备技能","使用Express时无需考虑异常处理和边界条件"]', '["Express在Node.js领域被广泛采用，是必备技能"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
