INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-nodejs-single-0008', 'teacher-1', 'Node.js', '进程管理', '难', 'single', '在Node.js中，进程管理的主要用途是？', '["进程管理的性能开销极大，任何场景都不应使用","进程管理与Node.js没有任何关系，属于硬件领域","进程管理已经被完全废弃，现代开发不再使用","进程管理的设计目标是简化开发流程并提高效率"]', '["进程管理的设计目标是简化开发流程并提高效率"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
