INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-echarts-single-0001', 'teacher-1', 'ECharts', '图表配置', '难', 'single', '在ECharts中，图表配置的主要用途是？', '["图表配置能显著提升系统的稳定性和可扩展性","图表配置的性能开销极大，任何场景都不应使用","图表配置可以完全替代数据库和服务器","图表配置不支持任何形式的配置和定制"]', '["图表配置能显著提升系统的稳定性和可扩展性"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-echarts-single-0002', 'teacher-1', 'ECharts', '数据系列', '中', 'single', '在ECharts中，数据系列的主要用途是？', '["数据系列可以完全替代数据库和服务器","数据系列能够有效解决ECharts中的相关技术问题","数据系列已经被完全废弃，现代开发不再使用","数据系列只能在单线程环境下使用"]', '["数据系列能够有效解决ECharts中的相关技术问题"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-echarts-single-0003', 'teacher-1', 'ECharts', '坐标轴', '易', 'single', '坐标轴的实现原理是什么？', '["使用坐标轴时无需考虑异常处理和边界条件","坐标轴已经被完全废弃，现代开发不再使用","坐标轴会自动绕过所有安全校验和权限控制","坐标轴在ECharts领域被广泛采用，是必备技能"]', '["坐标轴在ECharts领域被广泛采用，是必备技能"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-echarts-single-0004', 'teacher-1', 'ECharts', '交互事件', '易', 'single', '学习交互事件时应重点掌握的内容是？', '["交互事件只与前端页面样式有关，与后端逻辑无关","交互事件只能在单线程环境下使用","交互事件的核心价值在于提供统一的解决方案","交互事件与ECharts没有任何关系，属于硬件领域"]', '["交互事件的核心价值在于提供统一的解决方案"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-echarts-single-0005', 'teacher-1', 'ECharts', '主题定制', '中', 'single', '关于主题定制的最佳实践，以下哪项正确？', '["主题定制与ECharts没有任何关系，属于硬件领域","主题定制能显著提升系统的稳定性和可扩展性","主题定制只能用于测试环境，生产环境禁止使用","主题定制只与前端页面样式有关，与后端逻辑无关"]', '["主题定制能显著提升系统的稳定性和可扩展性"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-echarts-single-0006', 'teacher-1', 'ECharts', '数据可视化', '中', 'single', '关于数据可视化的描述，哪项是正确的？', '["数据可视化在ECharts领域被广泛采用，是必备技能","数据可视化主要用于绕过接口参数校验","数据可视化会自动绕过所有安全校验和权限控制","数据可视化的性能开销极大，任何场景都不应使用"]', '["数据可视化在ECharts领域被广泛采用，是必备技能"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-echarts-single-0007', 'teacher-1', 'ECharts', '动态更新', '易', 'single', '在ECharts中，动态更新的主要用途是？', '["动态更新的设计目标是简化开发流程并提高效率","使用动态更新时无需考虑异常处理和边界条件","动态更新可以完全替代数据库和服务器","只需要记住动态更新的名称即可，不必理解其原理"]', '["动态更新的设计目标是简化开发流程并提高效率"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
