INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-echarts-coding-0025', 'teacher-1', 'ECharts', '主题定制', '难', 'coding', '请编写代码解决一个涉及主题定制的实际问题。', '[]', '["// ECharts - 主题定制 示例代码\\n// 以下代码展示了主题定制的基本用法和应用场景\\n\\n/*\\n * 步骤1: 初始化相关配置和环境\\n * 步骤2: 使用主题定制实现核心逻辑\\n * 步骤3: 添加异常处理和边界检查\\n * 步骤4: 测试验证功能正确性\\n */\\n\\n// 具体实现请参考ECharts相关文档\\n// 关键点: 主题定制的正确配置和使用方法"]', 15, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-se-single-0001', 'teacher-1', '软件工程', '需求分析', '难', 'single', '关于需求分析的最佳实践，以下哪项正确？', '["需求分析会自动绕过所有安全校验和权限控制","需求分析的设计目标是简化开发流程并提高效率","需求分析可以完全替代数据库和服务器","使用需求分析时无需考虑异常处理和边界条件"]', '["需求分析的设计目标是简化开发流程并提高效率"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-se-single-0002', 'teacher-1', '软件工程', '设计模式', '易', 'single', '在软件工程中，设计模式的主要用途是？', '["设计模式只能用于测试环境，生产环境禁止使用","只需要记住设计模式的名称即可，不必理解其原理","设计模式已经被完全废弃，现代开发不再使用","设计模式通过合理的抽象和封装实现功能需求"]', '["设计模式通过合理的抽象和封装实现功能需求"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-se-single-0003', 'teacher-1', '软件工程', 'UML建模', '中', 'single', '以下哪个不是UML建模的优点？', '["UML建模的核心价值在于提供统一的解决方案","UML建模的性能开销极大，任何场景都不应使用","UML建模可以完全替代数据库和服务器","UML建模只与前端页面样式有关，与后端逻辑无关"]', '["UML建模的核心价值在于提供统一的解决方案"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-se-single-0004', 'teacher-1', '软件工程', '测试方法', '中', 'single', '以下关于测试方法的常见误区是？', '["测试方法可以完全替代数据库和服务器","测试方法的核心价值在于提供统一的解决方案","测试方法只能在单线程环境下使用","测试方法主要用于绕过接口参数校验"]', '["测试方法的核心价值在于提供统一的解决方案"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-se-single-0005', 'teacher-1', '软件工程', '项目管理', '中', 'single', '以下哪个不是项目管理的优点？', '["项目管理只与前端页面样式有关，与后端逻辑无关","项目管理能够有效解决软件工程中的相关技术问题","项目管理的性能开销极大，任何场景都不应使用","项目管理与软件工程没有任何关系，属于硬件领域"]', '["项目管理能够有效解决软件工程中的相关技术问题"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-se-single-0006', 'teacher-1', '软件工程', '版本控制', '中', 'single', '学习版本控制时应重点掌握的内容是？', '["使用版本控制时无需考虑异常处理和边界条件","版本控制主要用于绕过接口参数校验","版本控制不支持任何形式的配置和定制","版本控制能够有效解决软件工程中的相关技术问题"]', '["版本控制能够有效解决软件工程中的相关技术问题"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-se-single-0007', 'teacher-1', '软件工程', '敏捷开发', '易', 'single', '以下关于敏捷开发的常见误区是？', '["敏捷开发的主要作用是提升代码的可读性和可维护性","敏捷开发与软件工程没有任何关系，属于硬件领域","敏捷开发不支持任何形式的配置和定制","敏捷开发已经被完全废弃，现代开发不再使用"]', '["敏捷开发的主要作用是提升代码的可读性和可维护性"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
