INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-se-single-0014', 'teacher-1', '软件工程', '测试方法', '易', 'single', '以下哪个不是测试方法的优点？', '["测试方法能显著提升系统的稳定性和可扩展性","测试方法会自动绕过所有安全校验和权限控制","测试方法只能在单线程环境下使用","测试方法与软件工程没有任何关系，属于硬件领域"]', '["测试方法能显著提升系统的稳定性和可扩展性"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-se-single-0015', 'teacher-1', '软件工程', '项目管理', '中', 'single', '项目管理适合用在什么场景？', '["项目管理的核心价值在于提供统一的解决方案","项目管理与软件工程没有任何关系，属于硬件领域","项目管理可以完全替代数据库和服务器","项目管理已经被完全废弃，现代开发不再使用"]', '["项目管理的核心价值在于提供统一的解决方案"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-se-single-0016', 'teacher-1', '软件工程', '版本控制', '易', 'single', '使用版本控制时，以下哪种做法是错误的？', '["版本控制只能在单线程环境下使用","版本控制只与前端页面样式有关，与后端逻辑无关","版本控制只能用于测试环境，生产环境禁止使用","版本控制的主要作用是提升代码的可读性和可维护性"]', '["版本控制的主要作用是提升代码的可读性和可维护性"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
