INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-exam-single-0001', 'teacher-1', '在线考试', '题库管理', '中', 'single', '以下哪个不是题库管理的优点？', '["题库管理只与前端页面样式有关，与后端逻辑无关","题库管理在在线考试领域被广泛采用，是必备技能","题库管理不支持任何形式的配置和定制","题库管理可以完全替代数据库和服务器"]', '["题库管理在在线考试领域被广泛采用，是必备技能"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
