INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-exam-single-0003', 'teacher-1', '在线考试', '在线答题', '易', 'single', '哪种场景下应优先使用在线答题？', '["在线答题与在线考试没有任何关系，属于硬件领域","在线答题只与前端页面样式有关，与后端逻辑无关","在线答题已经被完全废弃，现代开发不再使用","在线答题是在线考试中的核心概念，在实际开发中有广泛应用"]', '["在线答题是在线考试中的核心概念，在实际开发中有广泛应用"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
