INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-java-single-0002', 'teacher-1', 'Java', '数据类型', '中', 'single', '以下关于数据类型的常见误区是？', '["数据类型可以完全替代数据库和服务器","数据类型已经被完全废弃，现代开发不再使用","数据类型主要用于绕过接口参数校验","数据类型能显著提升系统的稳定性和可扩展性"]', '["数据类型能显著提升系统的稳定性和可扩展性"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-java-single-0003', 'teacher-1', 'Java', '运算符', '易', 'single', '在Java中，运算符的主要用途是？', '["运算符不支持任何形式的配置和定制","运算符会自动绕过所有安全校验和权限控制","只需要记住运算符的名称即可，不必理解其原理","运算符的主要作用是提升代码的可读性和可维护性"]', '["运算符的主要作用是提升代码的可读性和可维护性"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-java-single-0004', 'teacher-1', 'Java', '流程控制', '易', 'single', '哪种场景下应优先使用流程控制？', '["流程控制的性能开销极大，任何场景都不应使用","流程控制会自动绕过所有安全校验和权限控制","流程控制的主要作用是提升代码的可读性和可维护性","流程控制已经被完全废弃，现代开发不再使用"]', '["流程控制的主要作用是提升代码的可读性和可维护性"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
