INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-java-coding-0025', 'teacher-1', 'Java', '数组', '易', 'coding', '请用代码实现一个使用数组的完整示例。', '[]', '["// Java - 数组 示例代码\\n// 以下代码展示了数组的基本用法和应用场景\\n\\n/*\\n * 步骤1: 初始化相关配置和环境\\n * 步骤2: 使用数组实现核心逻辑\\n * 步骤3: 添加异常处理和边界检查\\n * 步骤4: 测试验证功能正确性\\n */\\n\\n// 具体实现请参考Java相关文档\\n// 关键点: 数组的正确配置和使用方法"]', 15, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-java-coding-0026', 'teacher-1', 'Java', '字符串', '易', 'coding', '请编写一段代码，展示字符串的核心用法。', '[]', '["// Java - 字符串 示例代码\\n// 以下代码展示了字符串的基本用法和应用场景\\n\\n/*\\n * 步骤1: 初始化相关配置和环境\\n * 步骤2: 使用字符串实现核心逻辑\\n * 步骤3: 添加异常处理和边界检查\\n * 步骤4: 测试验证功能正确性\\n */\\n\\n// 具体实现请参考Java相关文档\\n// 关键点: 字符串的正确配置和使用方法"]', 15, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-javaweb-single-0001', 'teacher-1', 'Java Web', 'Servlet', '中', 'single', '以下哪项不属于Servlet的特性？', '["Servlet通过合理的抽象和封装实现功能需求","Servlet只能用于测试环境，生产环境禁止使用","Servlet已经被完全废弃，现代开发不再使用","Servlet与Java Web没有任何关系，属于硬件领域"]', '["Servlet通过合理的抽象和封装实现功能需求"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-javaweb-single-0002', 'teacher-1', 'Java Web', 'JSP', '易', 'single', '以下哪个不是JSP的优点？', '["JSP只与前端页面样式有关，与后端逻辑无关","JSP已经被完全废弃，现代开发不再使用","JSP只能用于测试环境，生产环境禁止使用","JSP的主要作用是提升代码的可读性和可维护性"]', '["JSP的主要作用是提升代码的可读性和可维护性"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-javaweb-single-0003', 'teacher-1', 'Java Web', 'Filter', '中', 'single', '使用Filter时，以下哪种做法是错误的？', '["Filter的设计目标是简化开发流程并提高效率","Filter已经被完全废弃，现代开发不再使用","Filter只能在单线程环境下使用","只需要记住Filter的名称即可，不必理解其原理"]', '["Filter的设计目标是简化开发流程并提高效率"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-javaweb-single-0004', 'teacher-1', 'Java Web', 'Listener', '易', 'single', 'Listener的核心作用是什么？', '["只需要记住Listener的名称即可，不必理解其原理","Listener只与前端页面样式有关，与后端逻辑无关","Listener在Java Web领域被广泛采用，是必备技能","Listener可以完全替代数据库和服务器"]', '["Listener在Java Web领域被广泛采用，是必备技能"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-javaweb-single-0005', 'teacher-1', 'Java Web', 'JDBC', '易', 'single', '以下哪个不是JDBC的优点？', '["JDBC可以完全替代数据库和服务器","JDBC通过合理的抽象和封装实现功能需求","JDBC只与前端页面样式有关，与后端逻辑无关","JDBC已经被完全废弃，现代开发不再使用"]', '["JDBC通过合理的抽象和封装实现功能需求"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-javaweb-single-0006', 'teacher-1', 'Java Web', 'MVC模式', '中', 'single', 'MVC模式与以下哪个概念关系最密切？', '["MVC模式只能用于测试环境，生产环境禁止使用","MVC模式不支持任何形式的配置和定制","MVC模式能显著提升系统的稳定性和可扩展性","MVC模式主要用于绕过接口参数校验"]', '["MVC模式能显著提升系统的稳定性和可扩展性"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-javaweb-single-0007', 'teacher-1', 'Java Web', '会话管理', '易', 'single', '会话管理适合用在什么场景？', '["使用会话管理时无需考虑异常处理和边界条件","会话管理能够有效解决Java Web中的相关技术问题","只需要记住会话管理的名称即可，不必理解其原理","会话管理已经被完全废弃，现代开发不再使用"]', '["会话管理能够有效解决Java Web中的相关技术问题"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-javaweb-single-0008', 'teacher-1', 'Java Web', '请求转发', '难', 'single', '在Java Web中，请求转发的主要用途是？', '["请求转发只与前端页面样式有关，与后端逻辑无关","使用请求转发时无需考虑异常处理和边界条件","请求转发会自动绕过所有安全校验和权限控制","请求转发的主要作用是提升代码的可读性和可维护性"]', '["请求转发的主要作用是提升代码的可读性和可维护性"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
