INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-javaweb-single-0020', 'teacher-1', 'Java Web', '部署配置', '难', 'single', '以下关于部署配置的常见误区是？', '["部署配置已经被完全废弃，现代开发不再使用","部署配置在Java Web领域被广泛采用，是必备技能","部署配置可以完全替代数据库和服务器","部署配置只能在单线程环境下使用"]', '["部署配置在Java Web领域被广泛采用，是必备技能"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-javaweb-single-0021', 'teacher-1', 'Java Web', 'Servlet', '难', 'single', 'Servlet适合用在什么场景？', '["Servlet能显著提升系统的稳定性和可扩展性","Servlet可以完全替代数据库和服务器","Servlet已经被完全废弃，现代开发不再使用","Servlet主要用于绕过接口参数校验"]', '["Servlet能显著提升系统的稳定性和可扩展性"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-javaweb-single-0022', 'teacher-1', 'Java Web', 'JSP', '难', 'single', '哪种场景下应优先使用JSP？', '["JSP能够有效解决Java Web中的相关技术问题","JSP与Java Web没有任何关系，属于硬件领域","JSP会自动绕过所有安全校验和权限控制","只需要记住JSP的名称即可，不必理解其原理"]', '["JSP能够有效解决Java Web中的相关技术问题"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
