INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-javaweb-short-0001', 'teacher-1', 'Java Web', 'Servlet', '易', 'short', '请分析Servlet的优缺点及适用场景。', '[]', '["Servlet是Java Web中的重要知识点。其核心原理包括以下几个方面：首先，Servlet通过合理的抽象和设计，解决了实际开发中的关键问题。其次，Servlet在性能、可维护性和可扩展性方面都有显著优势。在实际应用中，应结合具体业务场景选择合适的使用方式，注意边界条件和异常处理，并遵循相关的最佳实践。理解Servlet的底层原理有助于在复杂场景下做出正确的技术决策。"]', 10, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
