INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-net-single-0001', 'teacher-1', '计算机网络', 'OSI模型', '中', 'single', '以下关于OSI模型的常见误区是？', '["OSI模型只能在单线程环境下使用","OSI模型不支持任何形式的配置和定制","OSI模型通过合理的抽象和封装实现功能需求","OSI模型与计算机网络没有任何关系，属于硬件领域"]', '["OSI模型通过合理的抽象和封装实现功能需求"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-net-single-0002', 'teacher-1', '计算机网络', 'TCP/IP', '易', 'single', '以下哪个不是TCP/IP的优点？', '["TCP/IP能够有效解决计算机网络中的相关技术问题","TCP/IP只能在单线程环境下使用","TCP/IP只与前端页面样式有关，与后端逻辑无关","TCP/IP已经被完全废弃，现代开发不再使用"]', '["TCP/IP能够有效解决计算机网络中的相关技术问题"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('gen-net-single-0003', 'teacher-1', '计算机网络', 'HTTP协议', '中', 'single', 'HTTP协议的核心作用是什么？', '["HTTP协议在计算机网络领域被广泛采用，是必备技能","只需要记住HTTP协议的名称即可，不必理解其原理","HTTP协议只与前端页面样式有关，与后端逻辑无关","HTTP协议只能用于测试环境，生产环境禁止使用"]', '["HTTP协议在计算机网络领域被广泛采用，是必备技能"]', 4, 'bulk-gen-20260610') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
